import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as t,e as r}from"./app-e59b1464.js";const s={},c=r('<h1 id="面试-jvm" tabindex="-1"><a class="header-anchor" href="#面试-jvm" aria-hidden="true">#</a> 面试-JVM</h1><h3 id="jvm内存分析-解释下堆和栈" tabindex="-1"><a class="header-anchor" href="#jvm内存分析-解释下堆和栈" aria-hidden="true">#</a> JVM内存分析，解释下堆和栈</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：JVM内存分析，解释下堆和栈</b></summary><p><b style="color:#f19977;">答：JVM内存结构主要分为堆内存、方法区和栈。堆内存时JVM中最大的一块内存地址。所有new出来的对象都存储在该区域。栈就是暂存数据的地方，栈中只保存基础数据类型的对象和自定义对象的引用，每个栈中的数据都是私有的，其它栈不能访问。方法区存放了要加载的类的信息如类名、修饰符、静态变量、构造函数等</b></p></details>',3),o=[c];function n(i,d){return a(),t("div",null,o)}const _=e(s,[["render",n],["__file","面试-JVM.html.vue"]]);export{_ as default};
